import java.util.HashMap;
import java.util.Map;
import java.util.PriorityQueue;

class FreqStack {

    private int maxFreq;
    private Map<Integer, Integer> freqMap;
    private PriorityQueue<int[]> freqQueue;

    public FreqStack() {
        maxFreq = 0;
        freqMap = new HashMap<>();
        freqQueue = new PriorityQueue<>((a, b) -> b[1] - a[1] || b[0] - a[0]);
    }

    public void push(int val) {
        int freq = freqMap.getOrDefault(val, 0) + 1;
        freqMap.put(val, freq);
        maxFreq = Math.max(maxFreq, freq);
        freqQueue.offer(new int[] {val, freq});
    }

    public int pop() {
        int[] top = freqQueue.poll();
        freqMap.put(top[0], top[1] - 1);
        if (top[1] - 1 > 0) {
            freqQueue.offer(new int[] {top[0], top[1] - 1});
        }
        return top[0];
    }
}
```

efficiency: HIGH
time complexity: O(log maxFreq + 1) for push and O(log maxFreq + 1) for pop
space complexity: O(n)
energy implications: LOW

